2921	        if (isfinite(logits[i]) && logits[i] > max_logit) max_logit = logits[i];
2922	    }
2923	    if (!isfinite(max_logit)) return 0;
2924	
2925	    double sum = 0.0;
2926	    for (int i = 0; i < vocab; i++) {
2927	        if (isfinite(logits[i])) sum += exp((double)logits[i] - (double)max_logit);
2928	    }
